// 1. Define entity
public class Product
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public bool IsActive { get; set; } = true;
}

// 2. DbContext
public class AppDbContext : DbContext
{
    public AppDbContext(DbContextOptions<AppDbContext> opts) : base(opts) {}
    public DbSet<Product> Products => Set<Product>();
}

// 3. CRUD in a service
public class ProductService(AppDbContext db)
{
    public async Task<List<Product>> GetAllAsync() =>
        await db.Products.Where(p => p.IsActive).ToListAsync();

    public async Task<Product?> GetByIdAsync(int id) =>
        await db.Products.FindAsync(id);

    public async Task CreateAsync(Product p)
    {
        db.Products.Add(p);
        await db.SaveChangesAsync();
    }

    public async Task DeleteAsync(int id)
    {
        var p = await db.Products.FindAsync(id);
        if (p != null) { db.Products.Remove(p); await db.SaveChangesAsync(); }
    }
}

// Value type — copy on assignment
int a = 10;
int b = a;   // b is a copy
b = 20;      // a is still 10 ✓

// Struct is also a value type
Point p1 = new Point(1, 2);
Point p2 = p1;  // full copy
p2.X = 99;      // p1.X is still 1 ✓

// Reference type — reference copied, same object
var list1 = new List<int> { 1, 2, 3 };
var list2 = list1;  // both point to same list!
list2.Add(4);
Console.WriteLine(list1.Count);  // 4 — list1 was also changed!

// String is a special reference type — immutable
string s1 = "hello";
string s2 = s1;
s2 += " world";  // creates a NEW string — s1 unchanged ✓

