// Program.cs — middleware order matters!
var app = builder.Build();

// 1. Exception handler must be first — catches errors from everything below
app.UseExceptionHandler("/error");

// 2. HTTPS redirect
app.UseHttpsRedirection();

// 3. Static files
app.UseStaticFiles();

// 4. Routing — must be before Auth
app.UseRouting();

// 5. Auth — must be after Routing, before endpoints
app.UseAuthentication();
app.UseAuthorization();

// 6. Map endpoints last
app.MapControllers();

// Custom middleware
app.Use(async (context, next) => {
    Console.WriteLine($"→ {context.Request.Method} {context.Request.Path}");
    await next(context);  // call next middleware
    Console.WriteLine($"← {context.Response.StatusCode}");
});

