// Following SOLID
public interface IUserRepository { Task<User?> GetByIdAsync(int id); }
public interface IEmailService { Task SendAsync(string to, string msg); }

public class UserService(IUserRepository repo, IEmailService email)
{
    // Single responsibility: only user business logic
    public async Task<User> RegisterAsync(RegisterDto dto)
    {
        var user = new User(dto.Name, dto.Email);
        await repo.SaveAsync(user);
        await email.SendAsync(user.Email, "Welcome!");  // delegates to email service
        return user;
    }
}
