// ❌ IEnumerable — loads ALL 1 million users into RAM first!
public IEnumerable<User> GetActiveUsers()
{
    return _db.Users           // loads everything
        .AsEnumerable()        // <- now in memory
        .Where(u => u.IsActive); // filter in C#
}

// ✅ IQueryable — SQL: SELECT * FROM Users WHERE IsActive = 1
public IQueryable<User> GetActiveUsers()
{
    return _db.Users.Where(u => u.IsActive);  // still a query, not executed
}

// Composing queries — each Where adds to the SQL
public async Task<List<UserDto>> SearchAsync(string name, string dept, int page)
{
    IQueryable<User> query = _db.Users.Where(u => u.IsActive);
    if (!string.IsNullOrEmpty(name)) query = query.Where(u => u.Name.Contains(name));
    if (!string.IsNullOrEmpty(dept)) query = query.Where(u => u.Department == dept);

    return await query              // ONE SQL query with all filters + pagination
        .OrderBy(u => u.Name)
        .Skip((page - 1) * 20).Take(20)
        .Select(u => new UserDto(u.Id, u.Name, u.Email))
        .ToListAsync();             // <-- query executes HERE
}
